xpath.script:
document.addEventListener('DOMContentLoaded', function() {
    // 1. Dynamically inject the toggle button into the navbar
    var navbar = document.querySelector('header nav ul, header .navbar-nav, header ul.nav');
    if (!navbar) {
        navbar = document.querySelector('header nav, header .navbar');
    }
    if (navbar) {
        var li = document.createElement('li');
        li.className = 'nav-item';
        li.innerHTML = '<div class="theme-switch-wrapper nav-link">' +
           '<label class="theme-switch" for="themeCheckbox">' +
                '<input type="checkbox" id="themeCheckbox" />' +
                '<div class="theme-switch-slider"></div>' +
           '</label>' +
        '</div>';
        navbar.appendChild(li);
    }

    // 2. Apply saved theme or detect system preference
    var toggleSwitch = document.getElementById('themeCheckbox');
    var currentTheme = localStorage.getItem('theme');

    if (currentTheme) {
        document.documentElement.setAttribute('data-theme', currentTheme);
        if (currentTheme === 'dark' && toggleSwitch) {
            toggleSwitch.checked = true;
        }
    } else if (window.matchMedia('(prefers-color-scheme: dark)').matches) {
        document.documentElement.setAttribute('data-theme', 'dark');
        if (toggleSwitch) toggleSwitch.checked = true;
    } else {
        document.documentElement.setAttribute('data-theme', 'light');
    }

    // 3. Listen for toggle changes
    if (toggleSwitch) {
        toggleSwitch.addEventListener('change', function(e) {
            if (e.target.checked) {
                document.documentElement.setAttribute('data-theme', 'dark');
                localStorage.setItem('theme', 'dark');
            } else {
                document.documentElement.setAttribute('data-theme', 'light');
                localStorage.setItem('theme', 'light');
            }    
        }, false);
    }
});

t.script:
document.addEventListener("DOMContentLoaded", function () {
if(window.location.hash) {
var targetPane = window.location.hash;
var triggerEl = document.querySelector('button[data-bs-target="' + targetPane +
'-pane"]');
if(triggerEl) {
var tab = new bootstrap.Tab(triggerEl);
tab.show();
}
}
});
